#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Restore stability (exit-0-safe): stop the async-enrich engine (contention source w/o
proven benefit), kill stuck DDL/long-active queries, report conns. Returns to the healthy
sync-pool baseline. Reversible: async can be re-enabled after proper instrumentation."""
import os,sys,json,time,subprocess
def sh(c,t=30):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
def psql(q,t=18):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip().split('\n')[-1] if r.returncode==0 and r.stdout.strip() else None)
out={"kind":"stabilize","ts":int(time.time())}
try:
    out["active_before"]=psql("SELECT count(*) FROM pg_stat_activity WHERE state='active'")
    # stop async engine (all variants)
    out["async_stop"]=sh("for u in atlas-enrich-async@1 atlas-enrich-async-batch@1 atlas-enrich-async-ramp; do systemctl stop --no-block $u.service 2>/dev/null; systemctl disable $u.service 2>/dev/null; done; echo done")
    # kill stuck DDL + long-active (>120s) + idle-in-txn (>60s)
    out["killed_ddl"]=psql("SELECT count(*) FROM (SELECT pg_terminate_backend(pid) FROM pg_stat_activity WHERE query ILIKE 'ALTER TABLE%%' AND state='active' AND now()-query_start>interval '60s') x")
    out["killed_idle"]=psql("SELECT count(*) FROM (SELECT pg_terminate_backend(pid) FROM pg_stat_activity WHERE state='idle in transaction' AND now()-state_change>interval '60s') x")
    out["killed_longactive"]=psql("SELECT count(*) FROM (SELECT pg_terminate_backend(pid) FROM pg_stat_activity WHERE state='active' AND now()-query_start>interval '180s' AND query NOT ILIKE '%%pg_stat_activity%%') x")
    time.sleep(10)
    out["active_after"]=psql("SELECT count(*) FROM pg_stat_activity WHERE state='active'")
    out["total_after"]=psql("SELECT count(*)||'/'||current_setting('max_connections') FROM pg_stat_activity")
    out["pool_active"]=sh("systemctl list-units 'atlas-enrich-pool@*.service' --state=active --no-legend --plain 2>/dev/null|wc -l")
    out["async_state"]=sh("for u in atlas-enrich-async@1 atlas-enrich-async-batch@1; do echo $u=$(systemctl is-active $u.service 2>/dev/null); done")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/stabilize.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"stabilize","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
